data = [
    {"region": "Lima", "median": 28.0, "n": 40},
    {"region": "Cusco", "median": 22.5, "n": 32},
]
def view(region):
    row = next(r for r in data if r["region"] == region)
    return {
        "tooltip": f"{row['region']}: {row['median']} PEN (n={row['n']})",
        "filtro": region,
        "unidad": "PEN",
    }
print(view("Lima"))
print(view("Cusco")["tooltip"])
